        fd = load_form(tmp_path, "freq_test")
        assert fd is not None
        assert hasattr(fd, "dimensions")
        assert fd.dimensions == {"T": -1}

    def test_load_form_dimensionless_has_empty_dimensions(
        self, tmp_path: Path
    ) -> None:
        """Dimensionless form gets dimensions={}."""
