_CLAIM_ID_RE = re.compile(r'^claim\d+$')


def validate_claims(
    claim_files: list[LoadedClaimFile],
    concept_registry: dict[str, dict],
) -> ValidationResult:
    """Validate claim files against schema and compiler contract.

    Args:
